() => {
  const anchor = document.querySelector('otto-web-tool-bar-toggle-button[icon="library_add"]');
  const tooltip = document.querySelector('.cdk-overlay-pane:has(> gs-tooltip)');
  if (!anchor || !tooltip) return;

  const center = anchor.parentElement;
  if (center) {
    center.querySelectorAll('otto-web-tool-bar-toggle-button, gs-separator').forEach((node) => {
      if (node !== anchor) {
        node.style.display = 'none';
      }
    });
  }

  const wrap = tooltip.closest('.cdk-overlay-connected-position-bounding-box');
  if (wrap) {
    wrap.style.cssText = 'position:fixed;left:0;top:0;width:100vw;height:100vh;display:block;transform:none;pointer-events:none;';
  }

  tooltip.style.cssText = 'position:fixed;transform:none;pointer-events:none;';

  const anchorRect = anchor.getBoundingClientRect();
  const tooltipRect = tooltip.getBoundingClientRect();
  const left = Math.round(anchorRect.left + (anchorRect.width / 2) - (tooltipRect.width / 2));
  const top = Math.round(anchorRect.bottom + 8);

  tooltip.style.left = left + 'px';
  tooltip.style.top = top + 'px';
  tooltip.style.margin = '0';
}
